import{_ as i,o as e,c as r,a2 as l}from"./chunks/framework.BEgbRHOA.js";const m=JSON.parse('{"title":"Админ-панель (xcourier_admin)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier-admin/index.md","filePath":"guide/xcourier-admin/index.md","lastUpdated":1775746985000}'),t={name:"guide/xcourier-admin/index.md"};function o(n,a,d,s,c,u){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="админ-панель-xcourier-admin" tabindex="-1">Админ-панель (xcourier_admin) <a class="header-anchor" href="#админ-панель-xcourier-admin" aria-label="Permalink to &quot;Админ-панель (xcourier_admin)&quot;">​</a></h1><p>Мобильное приложение для администраторов платформы xkurier. Полный контроль над магазинами, менеджерами, контентом и аналитикой.</p><h2 id="для-кого" tabindex="-1">Для кого <a class="header-anchor" href="#для-кого" aria-label="Permalink to &quot;Для кого&quot;">​</a></h2><p>Владельцы бизнеса и администраторы платформы, которым нужен полный контроль над всеми аспектами системы.</p><h2 id="основные-возможности" tabindex="-1">Основные возможности <a class="header-anchor" href="#основные-возможности" aria-label="Permalink to &quot;Основные возможности&quot;">​</a></h2><ul><li>Просмотр всех заказов по всем магазинам</li><li>Аналитические отчёты по заказам</li><li>Управление магазинами (создание, редактирование, расписание)</li><li>Управление менеджерами (создание, привязка к магазину, блокировка)</li><li>Управление баннерами на главной странице клиентского приложения</li><li>Управление категориями товаров</li><li>Обработка обращений в поддержку</li><li>Настройки платежей (наличные, СБП)</li><li>Блокировка пользователей</li></ul><h2 id="авторизация" tabindex="-1">Авторизация <a class="header-anchor" href="#авторизация" aria-label="Permalink to &quot;Авторизация&quot;">​</a></h2><p>Администратор входит по email и паролю. Доступна регистрация нового администратора. Если аккаунт заблокирован, доступ ограничен.</p><h2 id="навигация" tabindex="-1">Навигация <a class="header-anchor" href="#навигация" aria-label="Permalink to &quot;Навигация&quot;">​</a></h2><p>Приложение использует боковой Drawer с разделами:</p><ul><li>Заказы</li><li>Отчёты по заказам</li><li>Магазины</li><li>Обращения в поддержку</li><li>Настройки (менеджеры, баннеры, категории, платежи, заблокированные пользователи)</li></ul><h2 id="технические-экраны" tabindex="-1">Технические экраны <a class="header-anchor" href="#технические-экраны" aria-label="Permalink to &quot;Технические экраны&quot;">​</a></h2><p>Приложение включает технические экраны для edge-case сценариев:</p><ul><li><strong>Force Update</strong> — принудительное обновление при выходе критической версии</li><li><strong>Maintenance</strong> — экран техобслуживания</li><li><strong>No Internet</strong> — экран отсутствия интернета</li><li><strong>Error</strong> — экран общей ошибки</li></ul><p>Эти экраны управляются через Firebase Remote Config.</p>',15)])])}const p=i(t,[["render",o]]);export{m as __pageData,p as default};
